import { useEffect, useState } from "react";
import { Navigate, Route, Routes } from "react-router-dom";
import { LoginForm } from "./components/auth/login-form";
import { SignupForm } from "./components/auth/signup-form";
import { DashboardLayout } from "./layouts/DashboardLayout";
import { authClient } from "./lib/auth-client";
import { DeveloperDetailPage } from "./pages/dashboard/DeveloperDetailPage";
import { DevelopersListPage } from "./pages/dashboard/DevelopersListPage";
import { ErrorsPage } from "./pages/dashboard/ErrorsPage";
import { LearningsPage } from "./pages/dashboard/LearningsPage";
import { OverviewPage } from "./pages/dashboard/OverviewPage";
import { ProjectDetailPage } from "./pages/dashboard/ProjectDetailPage";
import { ProjectsListPage } from "./pages/dashboard/ProjectsListPage";
import { ROIPage } from "./pages/dashboard/ROIPage";
import { SessionDetailPage } from "./pages/dashboard/SessionDetailPage";
import { SessionsListPage } from "./pages/dashboard/SessionsListPage";

type Page = "login" | "signup";

function getCliParams(): { cliCallback: string; state: string } | null {
	const params = new URLSearchParams(window.location.search);
	const cliCallback = params.get("cli_callback");
	const state = params.get("state");
	if (!cliCallback || !state) return null;
	try {
		const url = new URL(cliCallback);
		if (url.hostname !== "127.0.0.1") return null;
	} catch {
		return null;
	}
	return { cliCallback, state };
}

function App() {
	const { data: session, isPending } = authClient.useSession();
	const [page, setPage] = useState<Page>("login");
	const [cliRedirecting, setCliRedirecting] = useState(false);
	const cliParams = getCliParams();

	useEffect(() => {
		if (!session || !cliParams || cliRedirecting) return;
		setCliRedirecting(true);

		fetch("/api/cli-token", { credentials: "include" })
			.then((res) => res.json())
			.then((data: { token: string }) => {
				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
				window.location.href = redirectUrl;
			});
	}, [session, cliParams, cliRedirecting]);

	if (isPending) {
		return (
			<div className="flex min-h-screen items-center justify-center">
				<p className="text-muted-foreground">Loading...</p>
			</div>
		);
	}

	if (cliRedirecting) {
		return (
			<div className="flex min-h-screen items-center justify-center">
				<p className="text-muted-foreground">Completing CLI login...</p>
			</div>
		);
	}

	if (!session) {
		return (
			<div className="flex min-h-screen items-center justify-center">
				{page === "login" ? (
					<LoginForm onSwitchToSignup={() => setPage("signup")} />
				) : (
					<SignupForm onSwitchToLogin={() => setPage("login")} />
				)}
			</div>
		);
	}

	return (
		<Routes>
			<Route path="/" element={<Navigate to="/dashboard" replace />} />
			<Route path="/dashboard" element={<DashboardLayout />}>
				<Route index element={<OverviewPage />} />
				<Route path="developers" element={<DevelopersListPage />} />
				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
				<Route path="projects" element={<ProjectsListPage />} />
				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
				<Route path="sessions" element={<SessionsListPage />} />
				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
				<Route path="roi" element={<ROIPage />} />
				<Route path="errors" element={<ErrorsPage />} />
				<Route path="learnings" element={<LearningsPage />} />
			</Route>
			<Route path="*" element={<Navigate to="/dashboard" replace />} />
		</Routes>
	);
}

export default App;

import {
	Activity,
	AlertCircle,
	BookOpen,
	ChevronsLeft,
	ChevronsRight,
	Clock,
	DollarSign,
	FolderKanban,
	LayoutDashboard,
	UserCircle,
} from "lucide-react";
import { useState } from "react";
import { Link, useLocation } from "react-router-dom";
import { cn } from "../../lib/utils";
import { ThemeToggle } from "./ThemeToggle";

const navigation = [
	{ name: "Overview", href: "/dashboard", icon: LayoutDashboard },
	{ name: "Developers", href: "/dashboard/developers", icon: UserCircle },
	{ name: "Projects", href: "/dashboard/projects", icon: FolderKanban },
	{
		name: "ROI & Business Value",
		href: "/dashboard/roi",
		icon: DollarSign,
	},
	{ name: "Sessions", href: "/dashboard/sessions", icon: Clock },
	{ name: "Learnings", href: "/dashboard/learnings", icon: BookOpen },
	{ name: "Errors", href: "/dashboard/errors", icon: AlertCircle },
];

export function Sidebar() {
	const { pathname } = useLocation();
	const [collapsed, setCollapsed] = useState(false);

	return (
		<div
			className={cn(
				"relative flex h-full shrink-0 flex-col bg-surface border-r border-border z-20 transition-[width] duration-200 ease-in-out",
				collapsed ? "w-14" : "w-64",
			)}
		>
			<div className="flex h-10 items-center gap-1.5 px-4 overflow-hidden border-b border-border">
				<Activity className="h-5 w-5 shrink-0 text-accent" />
				{!collapsed && (
					<span className="text-sm font-bold text-heading whitespace-nowrap">
						Rudel Analytics
					</span>
				)}
			</div>

			<nav className="flex-1 px-2 pt-2 pb-1 flex flex-col gap-[1px]">
				{navigation.map((item) => {
					const isActive = pathname === item.href;
					const Icon = item.icon;

					return (
						<div key={item.name} className="relative group">
							<Link
								to={item.href}
								className={cn(
									"flex items-center gap-2 rounded-lg px-2 py-2 text-[0.8125rem] font-medium transition-colors duration-150",
									collapsed && "justify-center",
									isActive
										? "bg-hover text-heading"
										: "text-muted hover:bg-hover hover:text-foreground",
								)}
							>
								<Icon className="h-4 w-4 shrink-0" />
								{!collapsed && (
									<span className="whitespace-nowrap overflow-hidden">
										{item.name}
									</span>
								)}
							</Link>

							{collapsed && (
								<div className="absolute left-full top-1/2 -translate-y-1/2 ml-2 px-2.5 py-1.5 rounded-md bg-heading text-surface text-xs font-medium whitespace-nowrap opacity-0 pointer-events-none group-hover:opacity-100 transition-opacity duration-150 z-50">
									{item.name}
								</div>
							)}
						</div>
					);
				})}
			</nav>

			<div
				className={cn(
					"border-t border-border p-2 flex items-center",
					collapsed ? "justify-center" : "justify-between px-4",
				)}
			>
				{!collapsed && <p className="text-xs text-muted">Rudel v1.0</p>}
				<div
					className={cn(
						"flex items-center",
						collapsed ? "flex-col gap-2" : "gap-2",
					)}
				>
					<ThemeToggle />
					<button
						type="button"
						onClick={() => setCollapsed(!collapsed)}
						className="p-1 rounded-md text-muted hover:text-foreground hover:bg-hover transition-colors"
						title={collapsed ? "Expand sidebar" : "Collapse sidebar"}
					>
						{collapsed ? (
							<ChevronsRight className="h-4 w-4" />
						) : (
							<ChevronsLeft className="h-4 w-4" />
						)}
					</button>
				</div>
			</div>
		</div>
	);
}

