			<div
				className={cn(
					"border-t border-border p-2 flex items-center",
					collapsed ? "justify-center" : "justify-between px-4",
				)}
			>
				{!collapsed && <p className="text-xs text-muted">Rudel v1.0</p>}
				<div
					className={cn(
						"flex items-center",
						collapsed ? "flex-col gap-2" : "gap-2",
