14→export function Breadcrumb() {
15→	const { pathname } = useLocation();
16→	const segments = pathname.split("/").filter(Boolean);
17→
18→	const crumbs = segments.map((segment, index) => {
19→		const href = `/${segments.slice(0, index + 1).join("/")}`;
20→		const label = segmentLabels[segment] || decodeURIComponent(segment);
21→		const isLast = index === segments.length - 1;
22→
23→		return { href, label, isLast };
24→	});
25→
26→	return (
27→		<nav className="flex shrink-0 items-center gap-1 text-xs text-muted h-10 px-8 bg-surface border-b border-border">
28→			{crumbs.map((crumb, index) => (
29→				<span key={crumb.href} className="flex items-center gap-1">
30→					{index > 0 && <ChevronRight className="h-3 w-3" />}
31→					{crumb.isLast ? (
32→						<span className="text-subheading">{crumb.label}</span>
33→					) : (
34→						<Link
35→							to={crumb.href}
36→							className="hover:text-foreground transition-colors"
37→						>
38→							{crumb.label}
39→						</Link>
40→					)}
41→				</span>
42→			))}
43→		</nav>
44→	);
